import { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [isLogin, setIsLogin] = useState(false);
  const [isRegister, setIsRegister] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const [courses, setCourses] = useState([]);
  const [enrolled, setEnrolled] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [progress, setProgress] = useState({});

  const handleAuth = async () => {
    const url = isRegister
      ? "http://localhost:5000/register"
      : "http://localhost:5000/login";

    await axios.post(url, { email, password });
    setIsLogin(true);
  };

  useEffect(() => {
    if (isLogin) {
      axios.get("http://localhost:5000/courses").then((res) => {
        setCourses(res.data);
      });

      axios.get("http://localhost:5000/enrolled").then((res) => {
        setEnrolled(res.data);
      });
    }
  }, [isLogin]);

  const handleEnroll = async (course) => {
    await axios.post("http://localhost:5000/enroll", { course });

    const res = await axios.get("http://localhost:5000/enrolled");
    setEnrolled(res.data);
  };

  const markComplete = (id) => {
    setProgress({ ...progress, [id]: 100 });
  };

  // 🔐 LOGIN UI
  if (!isLogin) {
    return (
      <div style={styles.authContainer}>
        <div style={styles.authBox}>
          <h1 style={{ color: "hsl(122, 100%, 69%)" }}>🎓 EduVerse</h1>
          <h3>{isRegister ? "Create Account" : "Welcome Back"}</h3>

          <input
            style={styles.input}
            placeholder="Email"
            onChange={(e) => setEmail(e.target.value)}
          />
          <input
            style={styles.input}
            type="password"
            placeholder="Password"
            onChange={(e) => setPassword(e.target.value)}
          />

          <button style={styles.primaryBtn} onClick={handleAuth}>
            {isRegister ? "Register" : "Login"}
          </button>

          <p onClick={() => setIsRegister(!isRegister)} style={styles.link}>
            {isRegister
              ? "Already have account? Login"
              : "New here? Create account"}
          </p>
        </div>
      </div>
    );
  }

  // 🎥 VIDEO PAGE
  if (selectedCourse) {
    return (
      <div style={styles.videoPage}>
        <h2>{selectedCourse.title}</h2>

        <iframe
          width="900"
          height="450"
          src={selectedCourse.video}
          title="video"
          style={styles.video}
        />

        <br /><br />

        <button
          style={styles.primaryBtn}
          onClick={() => markComplete(selectedCourse.id)}
        >
          Mark Complete ✅
        </button>

        <h3>Progress: {progress[selectedCourse.id] || 0}%</h3>

        <button
          style={styles.secondaryBtn}
          onClick={() => setSelectedCourse(null)}
        >
          ⬅ Back
        </button>
      </div>
    );
  }

  // 📊 DASHBOARD
  return (
    <div style={styles.app}>
      {/* SIDEBAR */}
      <div style={styles.sidebar}>
        <h2>🎓 EduVerse</h2>

        <h4 style={{ marginTop: "20px" }}>My Courses</h4>

        {enrolled.map((c) => (
          <div
            key={c.id}
            style={styles.sidebarItem}
            onClick={() => setSelectedCourse(c)}
          >
            {c.title}
          </div>
        ))}

        {/* ✅ LOGOUT BUTTON */}
        <button
          style={styles.logoutBtn}
          onClick={() => {
            setIsLogin(false);
            setSelectedCourse(null);
          }}
        >
          Logout 🚪
        </button>
      </div>

      {/* MAIN CONTENT */}
      <div style={styles.content}>
        <h1>Explore Courses</h1>

        <div style={styles.grid}>
          {courses.map((course) => {
            const isEnrolled = enrolled.find(
              (c) => c.id === course.id
            );

            return (
              <div key={course.id} style={styles.card}>
                <img src={course.image} style={styles.image} alt="course" />

                <div style={{ padding: "15px" }}>
                  <h3>{course.title}</h3>
                  <p style={{ color: "#777" }}>{course.description}</p>

                  {!isEnrolled ? (
                    <button
                      style={styles.primaryBtn}
                      onClick={() => handleEnroll(course)}
                    >
                      Enroll Now
                    </button>
                  ) : (
                    <>
                      <button style={styles.successBtn}>
                        Enrolled ✅
                      </button>

                      <br /><br />

                      <button
                        style={styles.secondaryBtn}
                        onClick={() => setSelectedCourse(course)}
                      >
                        Watch Course 🎥
                      </button>
                    </>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// 🎨 MODERN UI STYLES
const styles = {
  authContainer: {
    height: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    background: "linear-gradient(135deg,#667eea,#764ba2)",
  },
  authBox: {
    background: "white",
    padding: "40px",
    borderRadius: "15px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.2)",
    textAlign: "center",
  },
  input: {
    display: "block",
    margin: "15px auto",
    padding: "12px",
    width: "260px",
    borderRadius: "8px",
    border: "1px solid #ddd",
  },
  primaryBtn: {
    background: "#6C63FF",
    color: "white",
    padding: "10px 20px",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
  },
  secondaryBtn: {
    background: "#eee",
    padding: "8px 15px",
    borderRadius: "8px",
    border: "none",
    cursor: "pointer",
  },
  successBtn: {
    background: "green",
    color: "white",
    padding: "8px 15px",
    borderRadius: "8px",
    border: "none",
  },
  link: { color: "#6C63FF", cursor: "pointer" },

  app: { display: "flex", fontFamily: "Arial" },

  sidebar: {
    width: "250px",
    height: "100vh",
    background: "#1e1e2f",
    color: "white",
    padding: "20px",
  },
  sidebarItem: {
    padding: "10px",
    marginTop: "10px",
    background: "#2e2e42",
    borderRadius: "6px",
    cursor: "pointer",
  },
  logoutBtn: {
    marginTop: "30px",
    padding: "10px",
    width: "100%",
    background: "#ff4d4d",
    color: "white",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
  },

  content: {
    flex: 1,
    padding: "30px",
    background: "#f5f7fa",
  },

  grid: {
    display: "flex",
    gap: "20px",
    flexWrap: "wrap",
  },

  card: {
    width: "280px",
    background: "white",
    borderRadius: "12px",
    overflow: "hidden",
    boxShadow: "0 6px 15px rgba(0,0,0,0.15)",
  },

  image: {
    width: "100%",
    height: "150px",
    objectFit: "contain",
    background: "#f4f4f4",
    padding: "10px",
  },

  videoPage: {
    textAlign: "center",
    padding: "40px",
    background: "#f5f7fa",
    height: "100vh",
  },
  video: {
    borderRadius: "12px",
    boxShadow: "0 10px 20px rgba(0,0,0,0.2)",
  },
};

export default App;
